1	export type Cell = [number, number];
2	
3	const key = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const isNeighbor = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
6	  (ax !== bx || ay !== by) && Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
7	
8	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
9	  cells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const livesNextGeneration = (isAlive: boolean, neighbors: number): boolean =>
12	  neighbors === 3 || (isAlive && neighbors === 2);
13	
14	const candidateCells = (cells: Cell[]): Cell[] => {
15	  const candidates = new Map<string, Cell>();
16	  for (const [x, y] of cells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        const candidate: Cell = [x + dx, y + dy];
20	        candidates.set(key(candidate), candidate);
21	      }
22	    }
23	  }
24	  return [...candidates.values()];
25	};
26	
27	export function nextGeneration(cells: Cell[]): Cell[] {
28	  const liveKeys = new Set(cells.map(key));
29	  return candidateCells(cells).filter((cell) =>
30	    livesNextGeneration(liveKeys.has(key(cell)), countNeighbors(cell, cells))
31	  );
32	}
33

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should preserve a 2x2 block (still life - all cells have 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(horizontal));
26	  });
27	  it("should kill an overpopulated cell (more than 3 neighbors)", () => {
28	    // Center cell (1,1) has 4 live neighbors → dies
29	    const input: [number, number][] = [
30	      [0, 0], [1, 0], [2, 0],
31	      [1, 1],
32	      [0, 2], [1, 2], [2, 2],
33	    ];
34	    const result = nextGeneration(input);
35	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
36	  });
37	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
38	    // Dead cell (1,1) has 3 live neighbors: (0,0), (1,0), (0,1)
39	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
40	    const result = nextGeneration(input);
41	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
42	  });
43	  it.todo("should handle negative coordinates correctly");
44	});
